#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum StockIconStep {
    Horizontal(u8),
    Vertical(u8),
}

impl StockIconStep {
    fn apply(self, address: u16) -> u16 {
        let [mut x, mut y] = address.to_be_bytes();
        match self {
            Self::Horizontal(delta) => x = x.wrapping_add(delta),
            Self::Vertical(delta) => y = y.wrapping_add(delta),
        }
        u16::from_be_bytes([x, y])
    }
}

