    #[test]
    fn player_display_skips_status_and_outside_scanline_band() {
        let mut machine = ArcadeMachine::new();
        machine.step(CabinetInput {
            start_one: true,
            ..CabinetInput::NONE
        });
        let picture = red_label_object_picture_address("PLAPIC").expect("PLAPIC address");
        write_object_footprint(&mut machine, 0x2080, picture, 0xCC);
        machine.memory.write_byte(0xA0BA, 0x10).expect("set STATUS");

        assert_eq!(
            machine
                .red_label_display_player_picture_in_band(0x90, 0x70)
                .expect("status-blocked PRDISP"),
            RedLabelPlayerDisplay::StatusBlocked { status: 0x10 }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA077..0xA078),
            Some(&[0x90][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x2080..0x2081),
            Some(&[0xCC][..])
        );

        machine.memory.write_byte(0xA0BA, 0).expect("clear STATUS");
        assert_eq!(
            machine
                .red_label_display_player_picture_in_band(0x70, 0x60)
                .expect("outside-band PRDISP"),
            RedLabelPlayerDisplay::OutsideBand {
                status: 0,
                upper_bound: 0x70,
                lower_bound: 0x60,
                player_y: 0x80,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA077..0xA078),
            Some(&[0x70][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x2080..0x2081),
            Some(&[0xCC][..])
        );
    }

