    #[test]
    fn color_ram_asset_captures_crtab() {
        let table = red_label_color_ram_table("CRTAB").expect("CRTAB asset");

        assert_eq!(table.label, "CRTAB");
        assert_eq!(table.address, 0xF8BE);
        assert_eq!(table.bytes, CRTAB_BYTES);

        let error = parse_color_ram_tables("label\taddress\tbytes\tsource\nCRTAB\t0xF8BE\t00\t\n")
            .expect_err("missing source");
        assert!(error.contains("empty source"));
    }

    #[test]
    fn color_cycle_asset_captures_coltab_and_tctab() {
        let coltab = red_label_color_cycle_table("COLTAB").expect("COLTAB asset");
        assert_eq!(coltab.label, "COLTAB");
        assert_eq!(coltab.address, 0xE799);
        assert_eq!(coltab.bytes.len(), 37);
        assert_eq!(
            &coltab.bytes[0..8],
            &[0x38, 0x39, 0x3A, 0x3B, 0x3C, 0x3D, 0x3E, 0x3F]
        );
        assert_eq!(&coltab.bytes[32..37], &[0xBF, 0x3F, 0x3E, 0x3C, 0x00]);

        let tctab = red_label_color_cycle_table("TCTAB").expect("TCTAB asset");
        assert_eq!(tctab.label, "TCTAB");
        assert_eq!(tctab.address, 0xF45B);
        assert_eq!(
            tctab.bytes,
            [0x81, 0x81, 0x2F, 0x81, 0x2F, 0x07, 0x2F, 0x81, 0x07]
        );

        let error =
            parse_color_cycle_tables("label\taddress\tbytes\tsource\nCOLTAB\t0xE799\t00\t\n")
                .expect_err("missing source");
        assert!(error.contains("empty source"));
    }

    #[test]
    fn crinit_copies_crtab_into_pcram() {
        let mut memory =
            super::RedLabelRuntimeMemory::new_initialized().expect("initialized runtime memory");
        for address in 0xA026..0xA036 {
            memory.write_byte(address, 0xEE).expect("dirty PCRAM byte");
        }

        let init = memory
            .initialize_color_ram_from_crtab()
            .expect("CRINIT color RAM");

        assert_eq!(
            init,
            RedLabelColorRamInit {
                source_label: String::from("CRTAB"),
                source_address: 0xF8BE,
                target_start: 0xA026,
                target_end: 0xA036,
                bytes: CRTAB_BYTES.to_vec(),
            }
        );
        assert_eq!(memory.ram_range(0xA026..0xA036), Some(&CRTAB_BYTES[..]));
    }

