    #[test]
    fn stout_moves_draws_and_blinks_source_star_bytes() {
        let mut memory =
            super::RedLabelRuntimeMemory::new_initialized().expect("initialized runtime memory");
        fill_source_valid_stars(&mut memory);
        write_star_entry(&mut memory, 0, 0x20, 0x50, 0x77);
        write_star_entry(&mut memory, 1, 0x9B, 0x51, 0x11);
        write_star_entry(&mut memory, 2, 0x00, 0x52, 0x22);
        memory.write_byte(0xA0AE, 3).expect("set STRCNT");
        memory.write_word(0xA020, 0x0140).expect("set BGL");
        memory.write_word(0xA022, 0x0080).expect("set BGLX");
        memory.write_byte(0xA0DF, 0x01).expect("set SEED");
        for entry_index in 0..16 {
            let base = 0xAF9D + entry_index * 4;
            let screen_address = memory.read_word(base).expect("star screen address");
            memory
                .write_byte(screen_address, 0xEE)
                .expect("prime old star byte");
        }

        let output = memory.output_stars().expect("STOUT/SBLNK");

        assert_eq!(
            output,
            RedLabelStarOutput::Updated {
                movement: 0xFF,
                phase_mask: 0xF0,
                star_count: 3,
                blink: RedLabelStarBlink {
                    selected_table_address: 0xAF9D,
                    selected_offset: 0,
                    color: 0x00,
                    hyper: None,
                },
            }
        );
        assert_eq!(memory.ram_range(0xA06F..0xA071), Some(&[0xFF, 0x00][..]));
        assert_eq!(memory.ram_range(0xA071..0xA072), Some(&[0xF0][..]));
        assert_eq!(memory.ram_range(0x2050..0x2051), Some(&[0x00][..]));
        assert_eq!(memory.ram_range(0x9B51..0x9B52), Some(&[0x00][..]));
        assert_eq!(memory.ram_range(0x0052..0x0053), Some(&[0x00][..]));
        assert_eq!(memory.ram_range(0x1F50..0x1F51), Some(&[0x70][..]));
        assert_eq!(memory.ram_range(0x9A51..0x9A52), Some(&[0x10][..]));
        assert_eq!(memory.ram_range(0x9B52..0x9B53), Some(&[0x20][..]));
        assert_eq!(
            memory.ram_range(0xAF9D..0xAFA0),
            Some(&[0x1F, 0x50, 0x00][..])
        );
    }

    #[test]
    fn stout_honors_status_star_disable_bit() {
        let mut memory =
            super::RedLabelRuntimeMemory::new_initialized().expect("initialized runtime memory");
        fill_source_valid_stars(&mut memory);
        write_star_entry(&mut memory, 0, 0x20, 0x50, 0x77);
        memory
            .write_byte(0x2050, 0xEE)
            .expect("prime old star byte");
        memory.write_byte(0xA0AE, 1).expect("set STRCNT");
        memory.write_word(0xA020, 0x0140).expect("set BGL");
        memory.write_word(0xA022, 0x0080).expect("set BGLX");
        memory.write_byte(0xA0BA, 0x20).expect("disable stars");

        let output = memory.output_stars().expect("STOUT status guard");

        assert_eq!(output, RedLabelStarOutput::StatusBlocked { status: 0x20 });
        assert_eq!(memory.ram_range(0x2050..0x2051), Some(&[0xEE][..]));
        assert_eq!(
            memory.ram_range(0xAF9D..0xAFA0),
            Some(&[0x20, 0x50, 0x77][..])
        );
        assert_eq!(
            memory.ram_range(0xA056..0xA059),
            Some(&[0x00, 0x00, 0x00][..])
        );
    }

    #[test]
    fn sblnk_preserves_source_ram_blast_path() {
        let mut memory =
            super::RedLabelRuntimeMemory::new_initialized().expect("initialized runtime memory");
        fill_source_valid_stars(&mut memory);
        write_star_entry(&mut memory, 0, 0x20, 0x50, 0x77);
        write_star_entry(&mut memory, 8, 0x30, 0x60, 0x66);
        memory.write_byte(0xA0AE, 1).expect("set STRCNT");
        memory.write_word(0xA020, 0x0040).expect("set BGL");
        memory.write_word(0xA022, 0x0040).expect("set BGLX");
        memory.write_byte(0xA0BA, 0x02).expect("enable hyper Y");
        memory.write_byte(0xA0DF, 0xA0).expect("set SEED");
        memory.write_byte(0xA0E0, 0x88).expect("set HSEED");
        memory.write_byte(0xA0E1, 0x56).expect("set LSEED");
        memory
            .write_byte(0x8800, 0xEE)
            .expect("prime blasted clear target");

        let output = memory.output_stars().expect("STOUT/SBLNK ram blast");

        assert_eq!(
            output,
            RedLabelStarOutput::Updated {
                movement: 0x00,
                phase_mask: 0xF0,
                star_count: 1,
                blink: RedLabelStarBlink {
                    selected_table_address: 0xAFBD,
                    selected_offset: 0x20,
                    color: 0x77,
                    hyper: Some(RedLabelStarHyper {
                        target_table_address: 0xA056,
                        screen_clear_address: 0x8800,
                        x: 0x1C,
                        y: Some(0x6C),
                        ram_blast: Some(RedLabelStarRamBlast {
                            address: 0xA056,
                            value: 0x88,
                        }),
                    }),
                },
            }
        );
        assert_eq!(memory.ram_range(0xA056..0xA058), Some(&[0x1C, 0x6C][..]));
        assert_eq!(memory.ram_range(0x8800..0x8801), Some(&[0x00][..]));
        assert_eq!(
            memory.ram_range(0xAFBD..0xAFC0),
            Some(&[0x30, 0x60, 0x77][..])
        );
    }

