    #[test]
    fn thrust_process_cycles_table_pointers_and_sleeps() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(
                red_label_routine_address("THPROC").expect("THPROC address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make THPROC process")
            .process_address;
        machine
            .step_red_label_process_scheduler()
            .expect("schedule THPROC");
        machine.memory.write_word(0xA09F, 0xA182).expect("set THX");
        machine.memory.write_word(0xA0A8, 0xA1BA).expect("set FBX");

        let step = machine
            .red_label_step_thrust_process_current_process()
            .expect("THPROC step");

        assert_eq!(
            step,
            RedLabelThrustProcessStep {
                process_address: process,
                previous_thrust_pointer: 0xA182,
                next_thrust_pointer: 0xA162,
                previous_fireball_pointer: 0xA1BA,
                next_fireball_pointer: 0xA1A2,
                wakeup_address: 0xE9BF,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA09F..0xA0A1),
            Some(&[0xA1, 0x62][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0A8..0xA0AA),
            Some(&[0xA1, 0xA2][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 2..process + 5),
            Some(&[0xE9, 0xBF, 0x04][..])
        );
    }

