    #[test]
    fn start_game_from_credit_initializes_tables_and_starts_plstrt_process() {
        let mut machine = ArcadeMachine::new();
        let current = machine
            .red_label_make_process(0x9999, RED_LABEL_SYSTEM_PROCESS_TYPE)
            .expect("make current process");
        assert_eq!(current.process_address, 0xAAC5);
        machine
            .step_red_label_process_scheduler()
            .expect("make current process due");
        machine.memory.write_byte(0xA0B7, 1).expect("set PWRFLG");
        machine.memory.write_byte(0xA0BA, 0xFF).expect("set STATUS");
        machine.memory.write_byte(0xA037, 0x01).expect("set CREDIT");
        machine.memory.write_byte(0xA038, 0x55).expect("set CUNITS");
        machine.memory.write_byte(0xA039, 0x66).expect("set BUNITS");
        machine
            .memory
            .write_byte(0x0000, 0xAA)
            .expect("set VRAM start");
        machine
            .memory
            .write_byte(0x9BFF, 0xBB)
            .expect("set VRAM end");
        machine
            .memory
            .write_byte(0x9C00, 0xCC)
            .expect("set appearance RAM boundary");

        let start = machine
            .red_label_start_game_from_credit()
            .expect("START game");

        assert_eq!(
            start,
            RedLabelStartGame::Updated {
                power_flag: 1,
                status_before: 0xFF,
                initialized: Some(RedLabelStartGameInit {
                    killed_processes: 0,
                    screen_clear: screen_clear(),
                    player_start_process: RedLabelCreatedProcess {
                        process_address: 0xAAD4,
                        routine_address: red_label_routine_address("PLSTRT")
                            .expect("PLSTRT address"),
                        process_type: RED_LABEL_SYSTEM_PROCESS_TYPE,
                        class: RedLabelProcessClass::Regular,
                    },
                    ships: 3,
                    replay: 0x0100,
                }),
                credit: RedLabelStartCredit {
                    player_count_before: 0,
                    player_count_after: 1,
                    credit_before: 1,
                    credit_after: 0,
                    credit_cmos_backup: credit_backup(0x00),
                    top_display_required: false,
                },
            }
        );
        assert_eq!(machine.red_label_ram_range(0x0000..0x0001), Some(&[0][..]));
        assert_eq!(machine.red_label_ram_range(0x9BFF..0x9C00), Some(&[0][..]));
        assert_eq!(
            machine.red_label_ram_range(0x9C00..0x9C01),
            Some(&[0xCC][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA037..0xA03A),
            Some(&[0x00, 0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_cmos_range(0x7D..0x7F),
            Some(&[0xF0, 0xF0][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA08B..0xA08D),
            Some(&[0x01, 0x01][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0BA..0xA0BB),
            Some(&[0x7F][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA1C2..0xA1CD),
            Some(
                &[
                    0x00, 0x00, 0x00, 0x00, 0x01, 0x00, 0x00, 0x03, 0x01, 0x03, 0x0A
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(0xA1FF..0xA20A),
            Some(
                &[
                    0x00, 0x00, 0x00, 0x00, 0x01, 0x00, 0x00, 0x03, 0x01, 0x03, 0x0A
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(0xAAC5..0xAAC7),
            Some(&[0xAA, 0xD4][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xAAD4..0xAADB),
            Some(&[0x00, 0x00, 0xD9, 0x19, 0x01, 0x00, 0x00][..])
        );
    }

