    #[test]
    fn appearance_start_matches_apvct_apst_slot_allocation() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(0x1234, RED_LABEL_SYSTEM_PROCESS_TYPE)
            .expect("make process")
            .process_address;
        let object = machine
            .red_label_init_object_cell(
                process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("PLAPIC")
                        .expect("PLAPIC address"),
                    collision_vector_address: red_label_routine_address("NOKILL")
                        .expect("NOKILL address"),
                    scanner_color: 0x1234,
                },
            )
            .expect("init object")
            .object_address;
        machine.memory.write_word(0xA020, 0x1000).expect("set BGL");
        machine
            .memory
            .write_word(object + 0x0A, 0x1200)
            .expect("set object OX16");

        let appearance = machine
            .red_label_start_appearance_for_object(object)
            .expect("APVCT/APST");

        assert_eq!(
            appearance,
            RedLabelAppearanceStart {
                object_address: object,
                original_picture_address: 0xF9C1,
                final_picture_address: 0xF8EC,
                relative_x: 0x0200,
                slot_address: Some(0x9C00),
                erased_previous_slot: false,
                sound_loaded: Some(RedLabelLoadedSoundTable {
                    address: 0xD4EE,
                    priority: 0xD0,
                }),
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA065..0xA067),
            Some(&object.to_be_bytes()[..])
        );
        assert_eq!(
            machine.red_label_ram_range(object + 0x02..object + 0x15),
            Some(
                &[
                    0xF8, 0xEC, 0x00, 0x00, 0xAA, 0xC5, 0xED, 0xBC, 0x12, 0x00, 0x00, 0x00, 0x00,
                    0x00, 0x00, 0x00, 0x12, 0x34, 0x02,
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(0x9C00..0x9C0C),
            Some(&[0xAF, 0x00, 0xF9, 0xC1, 0x9C, 0x40, 0, 0, 0, 0, 0xA2, 0x3C][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0B0..0xA0B5),
            Some(&[0xD4, 0xEC, 0xD0, 0x01, 0x01][..])
        );
    }

