    #[test]
    fn terrain_blow_iteration_restarts_pass_until_final_sound_and_suicide() {
        let mut machine = ArcadeMachine::new();
        let loop_process = machine
            .red_label_make_process(
                red_label_routine_address("TBL4").expect("TBL4 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make looping TBL4 process")
            .process_address;
        machine
            .memory
            .write_byte(loop_process + 0x07, 0)
            .expect("set first iteration");
        machine.memory.write_byte(0xA0DF, 0).expect("set SEED");
        machine.memory.write_byte(0xA0E0, 0).expect("set HSEED");
        machine.memory.write_byte(0xA0E1, 0).expect("set LSEED");
        machine
            .memory
            .write_byte(0xB344, 0x70)
            .expect("seed altitude");
        machine
            .memory
            .write_byte(0xB310, 0x50)
            .expect("seed altitude");
        machine
            .step_red_label_process_scheduler()
            .expect("schedule looping TBL4");

        let RedLabelTerrainBlowProcessStep::IterationAdvancedSleeping {
            process_address,
            iteration,
            pass,
        } = machine
            .red_label_advance_terrain_blow_iteration_current_process()
            .expect("TBL4 loop step")
        else {
            panic!("expected TBL4 loop");
        };

        assert_eq!(process_address, loop_process);
        assert_eq!(iteration, 1);
        assert_eq!(pass.explosions.len(), 2);
        assert_eq!(
            pass.wakeup_address,
            red_label_routine_address("TBL3").unwrap()
        );
        assert_eq!(
            machine.red_label_ram_range(loop_process + 0x02..loop_process + 0x08),
            Some(&[0xEE, 0x44, 0x02, RED_LABEL_SYSTEM_PROCESS_TYPE, 0, 1,][..])
        );

        let final_process = machine
            .red_label_make_process(
                red_label_routine_address("TBL4").expect("TBL4 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make final TBL4 process")
            .process_address;
        machine
            .memory
            .write_byte(final_process + 0x07, 15)
            .expect("set final iteration");
        machine
            .step_red_label_process_scheduler()
            .expect("schedule final TBL4");

        let step = machine
            .red_label_advance_terrain_blow_iteration_current_process()
            .expect("TBL4 final step");

        assert_eq!(
            step,
            RedLabelTerrainBlowProcessStep::Completed {
                process_address: final_process,
                iteration: 16,
                sound_loaded: Some(RedLabelLoadedSoundTable {
                    address: 0xD4C7,
                    priority: 0xE8,
                }),
                killed_process: RedLabelKilledProcess {
                    killed_process_address: final_process,
                    previous_link_address: loop_process,
                },
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0B0..0xA0B5),
            Some(&[0xD4, 0xC5, 0xE8, 0x01, 0x01][..])
        );
    }

    #[test]
    fn player_restore_runs_prbres_prbst_probe_branch() {
        let mut machine = ArcadeMachine::new();
        let process = machine
            .red_label_make_process(
                red_label_routine_address("PLS1").expect("PLS1 address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make PLS1 process")
            .process_address;
        machine
            .step_red_label_process_scheduler()
            .expect("schedule PLS1");
        machine.memory.write_word(0xA08D, 0xA1C2).expect("set PLRX");
        machine.memory.write_byte(0xA1CC, 0).expect("clear PTARG");
        write_ram_bytes(&mut machine, 0xA1CD, &[0; 0x17]);
        machine
            .memory
            .write_byte(0xA1CD + 2, 2)
            .expect("seed PRBRES");
        machine.memory.write_byte(0xA0DF, 0x12).expect("set SEED");
        machine.memory.write_byte(0xA0E0, 0x20).expect("set HSEED");
        machine.memory.write_byte(0xA0E1, 0x40).expect("set LSEED");
        machine.memory.write_word(0xA020, 0).expect("set BGL");

        let mut expected_rng = RandState {
            seed: 0x12,
            hseed: 0x20,
            lseed: 0x40,
        };
        let mut expected_probe_fields = Vec::new();
        for _ in 0..2 {
            expected_rng.advance();
            let x16 = u16::from_be_bytes([
                (expected_rng.hseed & 0x3F).wrapping_add(0x10),
                expected_rng.lseed,
            ]);
            let y16 = u16::from_be_bytes([expected_rng.lseed.wrapping_shr(1) + RED_LABEL_Y_MIN, 0]);
            let xv_low = (expected_rng.seed & 0x3F).wrapping_sub(0x20);
            let xv = u16::from_be_bytes([if xv_low & 0x80 == 0 { 0 } else { 0xFF }, xv_low]);
            let mut yv_low = (expected_rng.lseed & 0x7F).wrapping_sub(0x40);
            if yv_low & 0x80 == 0 {
                yv_low |= 0x20;
            } else {
                yv_low &= 0xDF;
            }
            let yv = u16::from_be_bytes([if yv_low & 0x80 == 0 { 0 } else { 0xFF }, yv_low]);
            expected_probe_fields.push((x16, y16, xv, yv));
        }

        let finish = machine
            .red_label_finish_player_start_current_process()
            .expect("PLS1 finish");
        let RedLabelPlayerStart::GameExecReady { restore, .. } = finish else {
            panic!("expected PLS1 game exec return");
        };
        let probe_restore = restore.probe_restore.expect("probe restore branch");

        assert_eq!(probe_restore.reserve_count, 2);
        assert_eq!(probe_restore.active_count, 2);
        assert_eq!(probe_restore.created_objects.len(), 2);
        assert_eq!(machine.red_label_ram_range(0xA0FD..0xA0FE), Some(&[0][..]));
        assert_eq!(machine.red_label_ram_range(0xA114..0xA115), Some(&[2][..]));
        assert_eq!(machine.red_label_ram_range(0xA073..0xA074), Some(&[0][..]));
        assert_eq!(
            machine.red_label_ram_range(0xA0DF..0xA0E2),
            Some(&[expected_rng.seed, expected_rng.hseed, expected_rng.lseed][..])
        );

        for (index, object_address) in [0xA23C, 0xA253].into_iter().enumerate() {
            let (x16, y16, xv, yv) = expected_probe_fields[index];
            let probe = &probe_restore.created_objects[index];
            assert_eq!(probe.object.object_address, object_address);
            assert_eq!(
                probe.object.descriptor.picture_address,
                red_label_object_picture_address("PRBP1").expect("PRBP1 address")
            );
            assert_eq!(
                probe.object.descriptor.collision_vector_address,
                red_label_routine_address("PRBKIL").expect("PRBKIL address")
            );
            assert_eq!(probe.object.descriptor.scanner_color, 0xCCCC);
            assert_eq!(probe.x16, x16);
            assert_eq!(probe.y16, y16);
            assert_eq!(probe.xv, xv);
            assert_eq!(probe.yv, yv);
            assert_eq!(
                probe.appearance,
                RedLabelAppearanceStart {
                    object_address,
                    original_picture_address: red_label_object_picture_address("PRBP1")
                        .expect("PRBP1 address"),
                    final_picture_address: red_label_object_picture_address("NULOB")
                        .expect("NULOB address"),
                    relative_x: x16,
                    slot_address: Some(if index == 0 { 0x9C00 } else { 0x9C40 }),
                    erased_previous_slot: false,
                    sound_loaded: Some(RedLabelLoadedSoundTable {
                        address: 0xD4EE,
                        priority: 0xD0,
                    }),
                }
            );
            assert_eq!(
                machine.red_label_ram_range(object_address + 0x02..object_address + 0x15),
                Some(
                    &[
                        0xF8,
                        0xEC,
                        0,
                        0,
                        process.to_be_bytes()[0],
                        process.to_be_bytes()[1],
                        0xEB,
                        0x74,
                        x16.to_be_bytes()[0],
                        x16.to_be_bytes()[1],
                        y16.to_be_bytes()[0],
                        y16.to_be_bytes()[1],
                        xv.to_be_bytes()[0],
                        xv.to_be_bytes()[1],
                        yv.to_be_bytes()[0],
                        yv.to_be_bytes()[1],
                        0xCC,
                        0xCC,
                        0x02,
                    ][..]
                )
            );
        }

        assert_eq!(
            machine.red_label_ram_range(0xA065..0xA067),
            Some(&[0xA2, 0x53][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x9C00..0x9C0C),
            Some(&[0xAF, 0x00, 0xF8, 0xF7, 0x9C, 0x40, 0, 0, 0, 0, 0xA2, 0x3C][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x9C40..0x9C4C),
            Some(&[0xAF, 0x00, 0xF8, 0xF7, 0x9C, 0x80, 0, 0, 0, 0, 0xA2, 0x53][..])
        );
    }

    #[test]
    fn prbkil_collision_runs_kilo_rmax_mmsw_and_decrements_probe_count() {
        let mut machine = ArcadeMachine::new();
        let owner_process = machine
            .red_label_make_process(
                red_label_routine_address("PRBST").expect("PRBST address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make probe owner process")
            .process_address;
        let probe_object = machine
            .red_label_init_object_cell(
                owner_process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("PRBP1")
                        .expect("PRBP1 address"),
                    collision_vector_address: red_label_routine_address("PRBKIL")
                        .expect("PRBKIL address"),
                    scanner_color: 0xCCCC,
                },
            )
            .expect("init probe object")
            .object_address;
        machine
            .red_label_activate_object_cell(probe_object)
            .expect("activate probe object");
        machine.memory.write_byte(0xA114, 1).expect("set PRBCNT");
        machine.memory.write_byte(0xA116, 18).expect("set SWCNT");
        machine.memory.write_byte(0xA10D, 0x10).expect("set SWSTIM");
        machine.memory.write_byte(0xA10E, 0x3F).expect("set SWAC");
        machine.memory.write_word(0xA020, 0).expect("set BGL");
        machine
            .memory
            .write_word(0xA0DF, 0)
            .expect("set SEED/HSEED");
        machine.memory.write_byte(0xA0E1, 0).expect("set LSEED");
        machine
            .memory
            .write_byte(0xA08B, 1)
            .expect("set current player");
        machine
            .memory
            .write_word(0xA08D, 0xA1C2)
            .expect("set current player record");
        machine
            .memory
            .write_word(probe_object + 0x04, 0x5060)
            .expect("set OBJX/OBJY");
        machine
            .memory
            .write_word(probe_object + 0x0A, 0x2000)
            .expect("set OX16");
        machine
            .memory
            .write_word(probe_object + 0x0C, 0x6000)
            .expect("set OY16");

        let mut expected_rng = RandState {
            seed: 0,
            hseed: 0,
            lseed: 0,
        };
        expected_rng.advance();
        let requested_count = rmax(6, expected_rng.seed);
        let mut expected_spawn_fields = Vec::new();
        for _ in 0..2 {
            expected_rng.advance();
            let velocity_rand = expected_rng;
            let yv = sign_extend_u8_to_u16(velocity_rand.seed).wrapping_shl(1);
            let xv = sign_extend_u8_to_u16((velocity_rand.lseed & 0x3F).wrapping_sub(0x20));
            let acceleration = velocity_rand.lseed & 0x3F;
            let sleep_time = velocity_rand.hseed & 0x1F;
            expected_rng.advance();
            let shot_timer_rand = expected_rng;
            let shot_timer = rmax(0x10, shot_timer_rand.seed);
            expected_spawn_fields.push((
                velocity_rand,
                shot_timer_rand,
                xv,
                yv,
                acceleration,
                sleep_time,
                shot_timer,
            ));
        }

        let collision = machine
            .red_label_dispatch_object_collision_vector(probe_object)
            .expect("dispatch PRBKIL");
        let RedLabelObjectCollision::ProbeKilled(kill) = collision else {
            panic!("expected PRBKIL collision");
        };

        assert_eq!(requested_count, 5);
        assert_eq!(kill.requested_swarmer_count, requested_count);
        assert_eq!(kill.spawned_swarmers.len(), 2);
        assert_eq!(kill.active_probe_count, 0);
        assert_eq!(kill.object.object_address, probe_object);
        assert_eq!(kill.object.previous_object_link_address, 0xA065);
        assert_eq!(
            kill.object.score,
            RedLabelScoreOutcome {
                player_number: 1,
                bonus_awarded: false,
                sound_loaded: None,
            }
        );
        assert_eq!(
            kill.object.explosion,
            RedLabelExplosionStart {
                object_address: probe_object,
                picture_address: red_label_object_picture_address("PRBP1").unwrap(),
                relative_x: 0x2000,
                slot_address: Some(0x9C00),
                erased_previous_slot: false,
                top_left: Some(0x8060),
                center: Some(0x8264),
            }
        );
        assert_eq!(
            kill.object.sound_loaded,
            Some(RedLabelLoadedSoundTable {
                address: 0xD4F3,
                priority: 0xD0,
            })
        );
        assert_eq!(machine.red_label_ram_range(0xA114..0xA115), Some(&[0][..]));
        assert_eq!(machine.red_label_ram_range(0xA116..0xA117), Some(&[20][..]));
        assert_eq!(
            machine.red_label_ram_range(0xA073..0xA074),
            Some(&[requested_count - 2][..])
        );

        for (index, (process_address, object_address)) in
            [(0xAAD4, 0xA23C), (0xAAE3, 0xA253)].into_iter().enumerate()
        {
            let (velocity_rand, shot_timer_rand, xv, yv, acceleration, sleep_time, shot_timer) =
                expected_spawn_fields[index];
            let spawn = &kill.spawned_swarmers[index];
            assert_eq!(spawn.process.process_address, process_address);
            assert_eq!(
                spawn.process.routine_address,
                red_label_routine_address("MSWM").expect("MSWM address")
            );
            assert_eq!(spawn.object.object_address, object_address);
            assert_eq!(spawn.object.process_address, process_address);
            assert_eq!(spawn.x16, 0x2000);
            assert_eq!(spawn.y16, 0x6000);
            assert_eq!(spawn.xv, xv);
            assert_eq!(spawn.yv, yv);
            assert_eq!(spawn.acceleration, acceleration);
            assert_eq!(spawn.sleep_time, sleep_time);
            assert_eq!(spawn.shot_timer, shot_timer);
            assert_eq!(spawn.velocity_rand, velocity_rand);
            assert_eq!(spawn.shot_timer_rand, shot_timer_rand);
            assert_eq!(
                machine.red_label_ram_range(process_address + 0x02..process_address + 0x0C),
                Some(
                    &[
                        red_label_routine_address("MSWM").unwrap().to_be_bytes()[0],
                        red_label_routine_address("MSWM").unwrap().to_be_bytes()[1],
                        sleep_time,
                        RED_LABEL_SYSTEM_PROCESS_TYPE,
                        0,
                        object_address.to_be_bytes()[0],
                        object_address.to_be_bytes()[1],
                        acceleration,
                        0,
                        shot_timer,
                    ][..]
                )
            );
            assert_eq!(
                machine.red_label_ram_range(object_address + 0x02..object_address + 0x15),
                Some(
                    &[
                        red_label_object_picture_address("SWPIC1")
                            .unwrap()
                            .to_be_bytes()[0],
                        red_label_object_picture_address("SWPIC1")
                            .unwrap()
                            .to_be_bytes()[1],
                        0,
                        0,
                        process_address.to_be_bytes()[0],
                        process_address.to_be_bytes()[1],
                        red_label_routine_address("MSWKIL").unwrap().to_be_bytes()[0],
                        red_label_routine_address("MSWKIL").unwrap().to_be_bytes()[1],
                        0x20,
                        0,
                        0x60,
                        0,
                        xv.to_be_bytes()[0],
                        xv.to_be_bytes()[1],
                        yv.to_be_bytes()[0],
                        yv.to_be_bytes()[1],
                        0x24,
                        0x24,
                        0,
                    ][..]
                )
            );
        }
        assert_eq!(
            machine.red_label_ram_range(0xA065..0xA067),
            Some(&[0xA2, 0x53][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA067..0xA069),
            Some(&[0xA2, 0x6A][..])
        );
    }

