    #[test]
    fn akil1_player_catch_switches_fall_process_to_carried_and_starts_500_points() {
        let mut machine = ArcadeMachine::new();
        let falling_process = machine
            .red_label_make_process(
                red_label_routine_address("AFALL").expect("AFALL address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make AFALL process")
            .process_address;
        let astronaut = machine
            .red_label_init_object_cell(
                falling_process,
                RedLabelObjectDescriptor {
                    picture_address: red_label_object_picture_address("ASTP1")
                        .expect("ASTP1 address"),
                    collision_vector_address: red_label_routine_address("AKIL1")
                        .expect("AKIL1 address"),
                    scanner_color: 0x1111,
                },
            )
            .expect("init captured astronaut")
            .object_address;
        machine
            .red_label_activate_object_cell(astronaut)
            .expect("activate astronaut");
        machine
            .memory
            .write_word(astronaut + 0x06, falling_process)
            .expect("set OBJID");
        machine.memory.write_byte(0xA0DE, 1).expect("set PCFLG");

        let collision = machine
            .red_label_dispatch_object_collision_vector(astronaut)
            .expect("dispatch AKIL1");
        let RedLabelObjectCollision::CapturedAstronaut(captured) = collision else {
            panic!("expected AKIL1 captured astronaut collision");
        };

        assert_eq!(
            captured,
            RedLabelCapturedAstronautCollision::PlayerCaught {
                object_address: astronaut,
                falling_process_address: falling_process,
                score_process: Some(RedLabelCreatedProcess {
                    process_address: 0xAAD4,
                    routine_address: red_label_routine_address("P500").expect("P500 address"),
                    process_type: RED_LABEL_SYSTEM_PROCESS_TYPE,
                    class: RedLabelProcessClass::Regular,
                }),
                sound_loaded: Some(RedLabelLoadedSoundTable {
                    address: 0xD4DA,
                    priority: 0xE0,
                }),
            }
        );
        assert_eq!(
            machine.red_label_ram_range(falling_process + 0x02..falling_process + 0x04),
            Some(&[0xF2, 0x4C][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xAAD4 + 0x07..0xAAD4 + 0x09),
            Some(&astronaut.to_be_bytes()[..])
        );
    }

