    #[test]
    fn right_laser_loop_erases_and_suicides_at_screen_edge() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_laser_process(&mut machine, "LASR0");
        machine.memory.write_byte(0xA0B5, 1).expect("set LFLG");
        machine
            .memory
            .write_word(process + 0x07, 0x9800)
            .expect("set edge PD");
        machine
            .memory
            .write_word(process + 0x0B, 0x9500)
            .expect("set erase PD4");
        for address in [0x9500, 0x9600, 0x9700, 0x9800] {
            machine.memory.write_byte(address, 0xEE).expect("seed beam");
        }

        let step = machine
            .red_label_step_right_laser_current_process()
            .expect("LASR0 edge");

        assert_eq!(
            step,
            RedLabelLaserStep::Finished {
                process_address: process,
                direction: RedLabelLaserDirection::Right,
                reason: RedLabelLaserStopReason::ScreenEdge,
                collision: None,
                killed_process: RedLabelKilledProcess {
                    killed_process_address: process,
                    previous_link_address: 0xA05F,
                },
            }
        );
        for address in [0x9500, 0x9600, 0x9700, 0x9800] {
            assert_eq!(
                machine.red_label_ram_range(address..address + 1),
                Some(&[0x00][..])
            );
        }
        assert_eq!(
            machine.red_label_ram_range(0xA0B5..0xA0B6),
            Some(&[0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0x00, 0x00][..])
        );
    }

    #[test]
    fn right_laser_loop_collides_then_erases_and_suicides() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_laser_process(&mut machine, "LASR0");
        machine.memory.write_byte(0xA0B5, 1).expect("set LFLG");
        machine.memory.write_word(0xA0A4, 0xA142).expect("set FISX");
        write_ram_bytes(&mut machine, 0xA142, &[0xAA, 0xBB, 0xCC]);
        machine
            .memory
            .write_word(process + 0x07, 0x4652)
            .expect("set PD");
        machine
            .memory
            .write_word(process + 0x09, 0x4652)
            .expect("set PD2");
        machine
            .memory
            .write_word(process + 0x0B, 0x4652)
            .expect("set PD4");
        let object = machine
            .red_label_get_object_cell()
            .expect("get active object cell");
        machine
            .memory
            .write_word(
                object + 0x02,
                red_label_object_picture_address("LNDP1").expect("LNDP1"),
            )
            .expect("set object picture");
        machine
            .memory
            .write_word(object + 0x04, 0x4450)
            .expect("set object screen address");
        machine
            .memory
            .write_word(
                object + 0x08,
                red_label_routine_address("NOKILL").expect("NOKILL address"),
            )
            .expect("set NOKILL OCVECT");
        machine
            .red_label_activate_object_cell(object)
            .expect("activate object");

        let step = machine
            .red_label_step_right_laser_current_process()
            .expect("LASR0 collision");

        assert_eq!(
            step,
            RedLabelLaserStep::Finished {
                process_address: process,
                direction: RedLabelLaserDirection::Right,
                reason: RedLabelLaserStopReason::Collision,
                collision: Some(RedLabelObjectCollision::NoKill {
                    object_address: object
                }),
                killed_process: RedLabelKilledProcess {
                    killed_process_address: process,
                    previous_link_address: 0xA05F,
                },
            }
        );
        for address in [0x4652, 0x4752, 0x4852, 0x4952, 0x4A52] {
            assert_eq!(
                machine.red_label_ram_range(address..address + 1),
                Some(&[0x00][..])
            );
        }
        assert_eq!(
            machine.red_label_ram_range(0xA0F8..0xA0FA),
            Some(&[0x44, 0x52][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0B5..0xA0B6),
            Some(&[0x00][..])
        );
    }

    #[test]
    fn support_processes_cycle_laser_tie_and_bomb_colors_from_source_tables() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_support_process(&mut machine, "COLR");
        let colrlp = red_label_routine_address("COLRLP").expect("COLRLP address");

        let dispatch = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("COLR").expect("COLR address"),
            )
            .expect("dispatch COLR");
        assert_eq!(
            dispatch,
            RedLabelProcessDispatch::SupportProcess(
                RedLabelSupportProcessStep::LaserColorSleeping {
                    process_address: process,
                    color_index: 0,
                    color: 0x38,
                    wakeup_address: colrlp,
                },
            )
        );
        assert_eq!(machine.red_label_ram_range(0xA0B6..0xA0B7), Some(&[1][..]));
        assert_eq!(
            machine.red_label_ram_range(0xA027..0xA028),
            Some(&[0x38][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xE7, 0x84, 0x02][..])
        );

        machine
            .memory
            .write_byte(0xA0B6, 36)
            .expect("set COLTAB terminator index");
        let dispatch = machine
            .red_label_dispatch_translated_process_routine(colrlp)
            .expect("dispatch COLRLP terminator");
        assert_eq!(
            dispatch,
            RedLabelProcessDispatch::SupportProcess(
                RedLabelSupportProcessStep::LaserColorSleeping {
                    process_address: process,
                    color_index: 0,
                    color: 0x38,
                    wakeup_address: colrlp,
                },
            )
        );
        assert_eq!(machine.red_label_ram_range(0xA0B6..0xA0B7), Some(&[1][..]));

        let mut machine = ArcadeMachine::new();
        let process = schedule_support_process(&mut machine, "TIECOL");
        let tiecl = red_label_routine_address("TIECL").expect("TIECL address");
        let dispatch = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("TIECOL").expect("TIECOL address"),
            )
            .expect("dispatch TIECOL");
        assert_eq!(
            dispatch,
            RedLabelProcessDispatch::SupportProcess(
                RedLabelSupportProcessStep::TieColorPrimedSleeping {
                    process_address: process,
                    table_pointer: 0xF45B,
                    wakeup_address: tiecl,
                },
            )
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x09),
            Some(&[0xF4, 0x4A, 0x06, 0x00, 0x00, 0xF4, 0x5B][..])
        );

        let dispatch = machine
            .red_label_dispatch_translated_process_routine(tiecl)
            .expect("dispatch TIECL first triplet");
        assert_eq!(
            dispatch,
            RedLabelProcessDispatch::SupportProcess(
                RedLabelSupportProcessStep::TieColorWrittenSleeping {
                    process_address: process,
                    table_pointer: 0xF45B,
                    colors: [0x81, 0x81, 0x2F],
                    next_table_pointer: 0xF45E,
                    wakeup_address: tiecl,
                },
            )
        );
        assert_eq!(
            machine.red_label_ram_range(0xA033..0xA036),
            Some(&[0x81, 0x81, 0x2F][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x07..process + 0x09),
            Some(&[0xF4, 0x5E][..])
        );

        machine
            .memory
            .write_word(process + 0x07, 0xF461)
            .expect("seed final TCTAB triplet");
        let dispatch = machine
            .red_label_dispatch_translated_process_routine(tiecl)
            .expect("dispatch TIECL final triplet");
        assert_eq!(
            dispatch,
            RedLabelProcessDispatch::SupportProcess(
                RedLabelSupportProcessStep::TieColorWrittenSleeping {
                    process_address: process,
                    table_pointer: 0xF461,
                    colors: [0x2F, 0x81, 0x07],
                    next_table_pointer: 0xF45B,
                    wakeup_address: tiecl,
                },
            )
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x07..process + 0x09),
            Some(&[0xF4, 0x5B][..])
        );

        let mut machine = ArcadeMachine::new();
        let process = schedule_support_process(&mut machine, "CBOMB");
        let cbmb1 = red_label_routine_address("CBMB1").expect("CBMB1 address");
        let dispatch = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("CBOMB").expect("CBOMB address"),
            )
            .expect("dispatch CBOMB");
        assert_eq!(
            dispatch,
            RedLabelProcessDispatch::SupportProcess(
                RedLabelSupportProcessStep::BombColorPrimedSleeping {
                    process_address: process,
                    wakeup_address: cbmb1,
                },
            )
        );
        assert_eq!(
            machine.red_label_ram_range(0xA030..0xA033),
            Some(&[0xFF, 0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xF4, 0x72, 0x03][..])
        );

        let bmbd10 = red_label_object_image_address("BMBD10").expect("BMBD10 image address");
        let bmbd20 = red_label_object_image_address("BMBD20").expect("BMBD20 image address");
        machine.memory.write_byte(0xA0DF, 0x1A).expect("set SEED");
        machine.memory.write_word(0xA0A6, bmbd10).expect("set BAX");
        let dispatch = machine
            .red_label_dispatch_translated_process_routine(cbmb1)
            .expect("dispatch CBMB1");
        assert_eq!(
            dispatch,
            RedLabelProcessDispatch::SupportProcess(
                RedLabelSupportProcessStep::BombColorWrittenSleeping {
                    process_address: process,
                    seed: 0x1A,
                    color_index: 0x1A,
                    color: 0xF8,
                    previous_bomb_image: bmbd10,
                    next_bomb_image: bmbd20,
                    wakeup_address: red_label_routine_address("CBOMB").expect("CBOMB address"),
                },
            )
        );
        assert_eq!(
            machine.red_label_ram_range(0xA030..0xA033),
            Some(&[0xF8, 0x00, 0xF8][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0A6..0xA0A8),
            Some(&bmbd20.to_be_bytes()[..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xF4, 0x64, 0x06][..])
        );
    }

    #[test]
    fn support_process_flashes_player_up_score_and_dies_when_score_flag_is_set() {
        let mut machine = ArcadeMachine::new();
        seed_player_one_for_player_start(&mut machine);
        let process = schedule_support_process(&mut machine, "FLPUP");
        machine
            .memory
            .write_byte(0x0F1C, 0xEE)
            .expect("dirty score display");

        let dispatch = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("FLPUP").expect("FLPUP address"),
            )
            .expect("dispatch FLPUP");
        assert_eq!(
            dispatch,
            RedLabelProcessDispatch::SupportProcess(
                RedLabelSupportProcessStep::PlayerUpBlankedSleeping {
                    process_address: process,
                    player_number: 1,
                    block_clear: RedLabelBlockClear {
                        screen_address: 0x0F1C,
                        width: 24,
                        height: 8,
                    },
                    wakeup_address: red_label_routine_address("FLP2").expect("FLP2 address"),
                },
            )
        );
        assert_eq!(machine.red_label_ram_range(0x0F1C..0x0F1D), Some(&[0][..]));
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xF4, 0xB0, 0x08][..])
        );

        let dispatch = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("FLP2").expect("FLP2 address"),
            )
            .expect("dispatch FLP2");
        let RedLabelProcessDispatch::SupportProcess(
            RedLabelSupportProcessStep::PlayerUpRedrawnSleeping {
                process_address,
                score_transfer,
                wakeup_address,
            },
        ) = dispatch
        else {
            panic!("expected FLP2 redraw dispatch");
        };
        assert_eq!(process_address, process);
        assert_eq!(
            wakeup_address,
            red_label_routine_address("FLPUP").expect("FLPUP address")
        );
        assert_eq!(score_transfer.player_number, 1);
        assert_eq!(score_transfer.display_address, 0x0F1C);
        assert_eq!(score_transfer.score_address, 0xA1C3);
        assert_eq!(score_transfer.digits.len(), 6);
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xF4, 0x93, 0x0C][..])
        );

        let mut machine = ArcadeMachine::new();
        let process = schedule_support_process(&mut machine, "FLPUP");
        machine.memory.write_byte(0xA08A, 1).expect("set SCRFLG");
        let dispatch = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("FLPUP").expect("FLPUP address"),
            )
            .expect("dispatch FLPUP SCRFLG");
        assert_eq!(
            dispatch,
            RedLabelProcessDispatch::SupportProcess(RedLabelSupportProcessStep::PlayerUpCompleted(
                RedLabelKilledProcess {
                    killed_process_address: process,
                    previous_link_address: 0xA05F,
                }
            ),)
        );
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0x00, 0x00][..])
        );
    }

    #[test]
