    #[test]
    fn colide_shell_path_uses_picture_masks_and_dispatches_bkil() {
        let mut machine = ArcadeMachine::new();
        machine.step(CabinetInput {
            start_one: true,
            ..CabinetInput::NONE
        });
        let shell = setup_collision_bomb_shell(
            &mut machine,
            0x4050,
            red_label_routine_address("BKIL").expect("BKIL address"),
        );
        write_shell_footprint(&mut machine, 0x4050, 0xCC);

        let collision = machine
            .red_label_collide_picture_with_shells(
                red_label_object_picture_address("PLAPIC").expect("PLAPIC address"),
                0x4050,
            )
            .expect("COL0 shell collision")
            .expect("collision");

        assert_eq!(
            collision,
            RedLabelObjectCollision::BombShell(super::RedLabelBombCollision {
                shell_address: shell,
                old_screen_address: 0x4050,
                explosion_picture_address: 0xF951,
                score: RedLabelScoreOutcome {
                    player_number: 1,
                    bonus_awarded: false,
                    sound_loaded: None,
                },
                sound_loaded: Some(RedLabelLoadedSoundTable {
                    address: 0xD4E4,
                    priority: 0xE0,
                }),
            })
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0F8..0xA0FA),
            Some(&[0x40, 0x52][..])
        );
        assert_shell_footprint_cleared(&machine, 0x4050);
        assert_eq!(machine.snapshot().scores.player_one, 25);
    }

