    fn schedule_smart_bomb_process(machine: &mut ArcadeMachine) -> u16 {
        let process = machine
            .red_label_make_process(
                red_label_routine_address("SBOMB").expect("SBOMB address"),
                RED_LABEL_SYSTEM_PROCESS_TYPE,
            )
            .expect("make SBOMB process")
            .process_address;
        assert_eq!(
            machine
                .step_red_label_process_scheduler()
                .expect("schedule SBOMB")
                .expect("scheduled process")
                .process_address,
            process
        );
        process
    }

    fn schedule_laser_process(machine: &mut ArcadeMachine, routine: &str) -> u16 {
        let routine_address =
            red_label_routine_address(routine).unwrap_or_else(|_| panic!("{routine} address"));
        let process = machine
            .red_label_make_process(routine_address, RED_LABEL_SYSTEM_PROCESS_TYPE)
            .expect("make laser process")
            .process_address;
        assert_eq!(
            machine
                .step_red_label_process_scheduler()
                .expect("schedule laser process")
                .expect("scheduled process")
                .process_address,
            process
        );
        process
    }

