    #[test]
    fn hyperspace_entry_sets_status_and_sleeps_when_status_mask_allows() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_hyperspace_process(&mut machine);
        machine.memory.write_byte(0xA0BA, 0x02).expect("set STATUS");
        machine
            .memory
            .write_byte(0x0000, 0xAA)
            .expect("set VRAM start");
        machine
            .memory
            .write_byte(0x0029, 0xAB)
            .expect("set row before YMIN");
        machine
            .memory
            .write_byte(0x002A, 0xAC)
            .expect("set first active row");
        machine
            .memory
            .write_byte(0x9B29, 0xBA)
            .expect("set final page row before YMIN");
        machine
            .memory
            .write_byte(0x9B2A, 0xBC)
            .expect("set final page first active row");
        machine
            .memory
            .write_byte(0x9BFF, 0xBB)
            .expect("set VRAM end");
        machine
            .memory
            .write_byte(0x9C00, 0xCC)
            .expect("set appearance RAM boundary");

        let hyperspace = machine
            .red_label_start_hyperspace_current_process()
            .expect("HYPER entry");

        assert_eq!(
            hyperspace,
            RedLabelHyperspace::StartedSleeping {
                process_address: process,
                previous_status: 0x02,
                screen_clear: active_screen_clear(),
                wakeup_address: 0xE936,
            }
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0BA..0xA0BB),
            Some(&[0x77][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x0000..0x0001),
            Some(&[0xAA][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x0029..0x002A),
            Some(&[0xAB][..])
        );
        assert_eq!(machine.red_label_ram_range(0x002A..0x002B), Some(&[0][..]));
        assert_eq!(
            machine.red_label_ram_range(0x9B29..0x9B2A),
            Some(&[0xBA][..])
        );
        assert_eq!(machine.red_label_ram_range(0x9B2A..0x9B2B), Some(&[0][..]));
        assert_eq!(machine.red_label_ram_range(0x9BFF..0x9C00), Some(&[0][..]));
        assert_eq!(
            machine.red_label_ram_range(0x9C00..0x9C01),
            Some(&[0xCC][..])
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x05),
            Some(&[0xE9, 0x36, 0x0F][..])
        );
    }

    #[test]
    fn hyperspace_entry_suppresses_when_status_mask_blocks() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_hyperspace_process(&mut machine);
        machine.memory.write_byte(0xA0BA, 0x08).expect("set STATUS");

        let hyperspace = machine
            .red_label_start_hyperspace_current_process()
            .expect("guarded HYPER entry");

        assert_eq!(
            hyperspace,
            RedLabelHyperspace::Suppressed(RedLabelKilledProcess {
                killed_process_address: process,
                previous_link_address: 0xA05F,
            })
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0BA..0xA0BB),
            Some(&[0x08][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA05F..0xA061),
            Some(&[0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA061..0xA063),
            Some(&process.to_be_bytes()[..])
        );
    }

