    #[test]
    fn hyperspace_rematerialization_kills_shells_and_starts_appearance() {
        let mut machine = ArcadeMachine::new();
        let process = schedule_hyperspace_process(&mut machine);
        machine
            .red_label_start_hyperspace_current_process()
            .expect("HYPER entry");
        let first_shell = machine
            .red_label_get_object_cell()
            .expect("get first shell cell");
        let second_shell = machine
            .red_label_get_object_cell()
            .expect("get second shell cell");
        machine
            .memory
            .write_word(first_shell, second_shell)
            .expect("link first shell");
        machine
            .memory
            .write_word(second_shell, 0)
            .expect("terminate shell list");
        machine
            .memory
            .write_word(0xA06D, first_shell)
            .expect("set SPTR");
        machine.memory.write_byte(0xA099, 2).expect("set BMBCNT");
        machine.memory.write_byte(0xA0DF, 0x12).expect("set SEED");
        machine.memory.write_byte(0xA0E0, 0x35).expect("set HSEED");
        machine
            .memory
            .write_word(0xA0C5, 0x8034)
            .expect("set PLAY16");
        machine.memory.write_byte(0xA0FA, 1).expect("set ASTCNT");

        let dispatch = machine
            .red_label_dispatch_translated_process_routine(
                red_label_routine_address("HYP02").expect("HYP02 address"),
            )
            .expect("dispatch HYP02");

        assert_eq!(
            dispatch,
            RedLabelProcessDispatch::Hyperspace(RedLabelHyperspace::RematerializingSleeping {
                process_address: process,
                killed_shells: 2,
                seed_word: 0x1235,
                player_x16: 0x2000,
                player_y16: 0x4434,
                player_upper_left: 0x2044,
                player_direction: 0x0300,
                phony_object_address: second_shell,
                phony_picture_address: 0xF9C1,
                appearance: RedLabelAppearanceStart {
                    object_address: second_shell,
                    original_picture_address: 0xF9C1,
                    final_picture_address: 0xF8EC,
                    relative_x: 0x0800,
                    slot_address: Some(0x9C00),
                    erased_previous_slot: false,
                    sound_loaded: Some(RedLabelLoadedSoundTable {
                        address: 0xD4EE,
                        priority: 0xD0,
                    }),
                },
                wakeup_address: 0xE9AC,
            })
        );
        assert_eq!(
            machine.red_label_ram_range(0xA06D..0xA06F),
            Some(&[0x00, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA099..0xA09A),
            Some(&[0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA020..0xA024),
            Some(&[0x12, 0x35, 0x12, 0x35][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA0BA..0xA0CD),
            Some(
                &[
                    0x50, 0x03, 0x00, 0x00, 0x00, 0x00, 0x00, 0x20, 0x44, 0x20, 0x00, 0x44, 0x34,
                    0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(second_shell + 0x02..second_shell + 0x15),
            Some(
                &[
                    0xF8, 0xEC, 0x00, 0x00, 0xAA, 0xC5, 0xED, 0xBC, 0x1A, 0x35, 0x44, 0x34, 0x00,
                    0x00, 0x00, 0x00, 0x00, 0x00, 0x02,
                ][..]
            )
        );
        assert_eq!(
            machine.red_label_ram_range(process + 0x02..process + 0x09),
            Some(&[0xE9, 0xAC, 0x28, 0x00, 0x00, 0xA2, 0x53][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0x9C00..0x9C0C),
            Some(&[0xAF, 0x00, 0xF9, 0xC1, 0x9C, 0x40, 0, 0, 0, 0, 0xA2, 0x53][..])
        );
    }

