    #[test]
    fn step_shell_output_moves_live_shells_and_returns_output_dispatch() {
        let mut machine = ArcadeMachine::new();
        let source = machine
            .red_label_get_object_cell()
            .expect("get firing object cell");
        machine.memory.write_word(0xA020, 0x1040).expect("set BGL");
        machine.memory.write_word(0xA022, 0x1020).expect("set BGLX");
        machine
            .memory
            .write_word(source + 0x0A, 0x1100)
            .expect("set source OX16");
        machine
            .memory
            .write_word(source + 0x0C, 0x5001)
            .expect("set source OY16");
        let shell = machine
            .red_label_get_shell_cell(
                source,
                0x4444,
                RedLabelShellDescriptor {
                    output_routine_address: 0x1111,
                    picture_address: 0x2222,
                    kill_routine_address: 0x3333,
                },
            )
            .expect("get shell")
            .expect("allocated shell")
            .shell_address;
        machine
            .memory
            .write_word(shell + 0x04, 0x4455)
            .expect("set old shell screen address");
        machine
            .memory
            .write_word(shell + 0x0A, 0x2000)
            .expect("set shell OX16");
        machine
            .memory
            .write_word(shell + 0x0C, 0x5000)
            .expect("set shell OY16");
        machine
            .memory
            .write_word(shell + 0x0E, 0x0200)
            .expect("set shell OXV");
        machine
            .memory
            .write_word(shell + 0x10, 0x0100)
            .expect("set shell OYV");

        let steps = machine
            .red_label_step_shell_output()
            .expect("step shell output");

        assert_eq!(
            steps,
            vec![RedLabelShellStep::Output {
                shell_address: shell,
                old_screen_address: 0x4455,
                new_screen_address: 0x2151,
                output_routine_address: 0x1111,
            }]
        );
        assert_eq!(
            machine.red_label_ram_range(0xA09D..0xA09F),
            Some(&[0xFF, 0x80][..])
        );
        assert_eq!(
            machine.red_label_ram_range(shell + 0x04..shell + 0x06),
            Some(&[0x21, 0x51][..])
        );
        assert_eq!(
            machine.red_label_ram_range(shell + 0x0A..shell + 0x0E),
            Some(&[0x21, 0x80, 0x51, 0x00][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA06D..0xA06F),
            Some(&[0xA2, 0x53][..])
        );
        assert_eq!(
            machine.red_label_ram_range(0xA099..0xA09A),
            Some(&[0x01][..])
        );
    }

